// frontend/src/pages/JS AIDashboard.js
import React, { useState, useEffect } from 'react';
import { getRecommendations, checkAIHealth, predictCategory } from '../services/aiService';
import '../CSS App.css';

const AIDashboard = () => {
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(false);
  const [aiStatus, setAiStatus] = useState('checking');
  const [selectedJob, setSelectedJob] = useState(null);
  const [resumeCategory, setResumeCategory] = useState(null);

  const token = localStorage.getItem('token');

  useEffect(() => {
    checkAIStatus();
    loadRecommendations();
  }, []);

  const checkAIStatus = async () => {
    const status = await checkAIHealth();
    setAiStatus(status.status === 'AI Service Running' ? 'online' : 'offline');
  };

  const loadRecommendations = async () => {
    setLoading(true);
    const result = await getRecommendations(token);
    setRecommendations(result.recommendations || []);
    setResumeCategory(result.resume_category);
    setLoading(false);
  };

  const getMatchBadgeClass = (score) => {
    if (score >= 70) return 'badge-excellent';
    if (score >= 50) return 'badge-good';
    if (score >= 30) return 'badge-fair';
    return 'badge-poor';
  };

  const getMatchLevel = (score) => {
    if (score >= 70) return 'Excellent';
    if (score >= 50) return 'Good';
    if (score >= 30) return 'Fair';
    return 'Poor';
  };

  return (
    <div className="ai-dashboard">
      <div className="container">
        <h1>AI Job Matcher</h1>
        
        {/* AI Status Indicator */}
        <div className={`ai-status ${aiStatus}`}>
          {aiStatus === 'online' ? (
            <span>✅ AI Service is Online</span>
          ) : (
            <span>⚠️ AI Service is Offline - Starting Python API required</span>
          )}
        </div>

        {/* Resume Category Prediction */}
        {resumeCategory && (
          <div className="category-card">
            <h3>📊 Your Resume Category</h3>
            <div className="category-badge">{resumeCategory}</div>
            <p>Based on your resume content, AI predicts you're best suited for {resumeCategory} roles.</p>
          </div>
        )}

        {/* Job Recommendations */}
        <div className="recommendations-section">
          <h2>🎯 AI-Powered Job Recommendations</h2>
          {loading ? (
            <div className="loading">Analyzing your resume...</div>
          ) : recommendations.length === 0 ? (
            <div className="no-results">
              <p>No recommendations yet. Upload your resume to get started!</p>
            </div>
          ) : (
            <div className="job-list">
              {recommendations.map((job, index) => (
                <div 
                  key={index} 
                  className={`job-card ${getMatchBadgeClass(job.match_score)}`}
                  onClick={() => setSelectedJob(job)}
                >
                  <div className="job-header">
                    <h3>{job.job_title}</h3>
                    <div className="match-score">
                      <span className="score">{job.match_score}%</span>
                      <span className={`level ${getMatchBadgeClass(job.match_score)}`}>
                        {getMatchLevel(job.match_score)} Match
                      </span>
                    </div>
                  </div>
                  <div className="job-details">
                    <p>🎯 Matching Skills: {job.matching_skills_count} skills matched</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Selected Job Modal */}
        {selectedJob && (
          <div className="modal" onClick={() => setSelectedJob(null)}>
            <div className="modal-content" onClick={(e) => e.stopPropagation()}>
              <h2>{selectedJob.job_title}</h2>
              <div className="match-details">
                <div className="match-score-large">
                  Match Score: <strong>{selectedJob.match_score}%</strong>
                </div>
                <div className="match-level">
                  {getMatchLevel(selectedJob.match_score)} Match
                </div>
              </div>
              <button onClick={() => setSelectedJob(null)}>Close</button>
            </div>
          </div>
        )}
      </div>

      <style jsx>{`
        .ai-dashboard {
          padding: 20px;
          font-family: Arial, sans-serif;
        }
        .ai-status {
          padding: 10px;
          border-radius: 5px;
          margin-bottom: 20px;
        }
        .ai-status.online {
          background: #d4edda;
          color: #155724;
        }
        .ai-status.offline {
          background: #f8d7da;
          color: #721c24;
        }
        .category-card {
          background: #e8f4f8;
          padding: 15px;
          border-radius: 10px;
          margin-bottom: 20px;
        }
        .category-badge {
          display: inline-block;
          background: #007bff;
          color: white;
          padding: 5px 15px;
          border-radius: 20px;
          font-weight: bold;
        }
        .job-list {
          display: grid;
          gap: 15px;
        }
        .job-card {
          border: 1px solid #ddd;
          border-radius: 10px;
          padding: 15px;
          cursor: pointer;
          transition: transform 0.2s;
        }
        .job-card:hover {
          transform: translateY(-2px);
          box-shadow: 0 4px 8px rgba(0,0,0,0.1);
        }
        .job-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
        }
        .match-score {
          text-align: right;
        }
        .score {
          font-size: 20px;
          font-weight: bold;
          display: block;
        }
        .badge-excellent { border-left: 4px solid #28a745; }
        .badge-good { border-left: 4px solid #17a2b8; }
        .badge-fair { border-left: 4px solid #ffc107; }
        .badge-poor { border-left: 4px solid #dc3545; }
        .modal {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          background: rgba(0,0,0,0.5);
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .modal-content {
          background: white;
          padding: 20px;
          border-radius: 10px;
          width: 400px;
        }
      `}</style>
    </div>
  );
};

export default AIDashboard;
